const express = require('express');
const router = express.Router();

router.get('/api/users/:userId/profile', async (req, res) => {
  try {
    const requestedUserId = req.params.userId;
    const authenticatedUserId = req.user?.id;

    if (!authenticatedUserId) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    if (!requestedUserId || typeof requestedUserId !== 'string') {
      return res.status(400).json({ error: 'Invalid user ID' });
    }

    if (requestedUserId !== authenticatedUserId && !req.user.isAdmin) {
      return res.status(403).json({ error: 'Forbidden: Cannot access other user profiles' });
    }

    const userProfile = await getUserProfile(requestedUserId);

    if (!userProfile) {
      return res.status(404).json({ error: 'User not found' });
    }

    const sanitizedProfile = {
      id: userProfile.id,
      username: userProfile.username,
      email: userProfile.email,
      firstName: userProfile.firstName,
      lastName: userProfile.lastName,
      createdAt: userProfile.createdAt,
      updatedAt: userProfile.updatedAt
    };

    return res.status(200).json(sanitizedProfile);
  } catch (error) {
    console.error('Error fetching user profile:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

async function getUserProfile(userId) {
  return {
    id: userId,
    username: 'exampleuser',
    email: 'user@example.com',
    firstName: 'John',
    lastName: 'Doe',
    password: 'hashedpassword',
    createdAt: new Date(),
    updatedAt: new Date()
  };
}

module.exports = router;